<template><nav v-if="!hideOnSinglePage||pageCount>1" v-bind="$attrs" :class="classes" aria-label="分页"><template v-for="part in layoutParts" :key="part"><span v-if="part==='total'" class="mg-pagination__total">共 {{ total }} 条</span><select v-else-if="part==='sizes'" class="mg-pagination__sizes" :value="pageSize" :disabled="disabled" aria-label="每页条数" @change="changeSize"><option v-for="size in pageSizes" :key="size" :value="size">{{ size }} 条/页</option></select><button v-else-if="part==='prev'" type="button" class="mg-pagination__button" :disabled="disabled||current<=1" aria-label="上一页" @click="setPage(current-1)"><slot name="prev">‹</slot></button><div v-else-if="part==='pager'" class="mg-pagination__pager"><button v-for="page in pages" :key="String(page)" type="button" :class="['mg-pagination__button',{ 'is-active':page===current,'is-more':typeof page==='string'}]" :disabled="disabled||typeof page==='string'" :aria-current="page===current?'page':undefined" @click="typeof page==='number'&&setPage(page)">{{ page }}</button></div><button v-else-if="part==='next'" type="button" class="mg-pagination__button" :disabled="disabled||current>=pageCount" aria-label="下一页" @click="setPage(current+1)"><slot name="next">›</slot></button><span v-else-if="part==='jumper'" class="mg-pagination__jumper">前往 <input :value="current" type="number" :min="1" :max="pageCount" :disabled="disabled" aria-label="跳转页码" @change="jump"> 页</span><slot v-else-if="part==='slot'" /></template></nav></template>
<script setup lang="ts">
import{computed}from'vue';defineOptions({name:'MgPagination',inheritAttrs:false});const props=withDefaults(defineProps<{total?:number;pageSize?:number;defaultPageSize?:number;currentPage?:number;defaultCurrentPage?:number;pageCount?:number;pagerCount?:number;layout?:string;pageSizes?:number[];popperClass?:string;prevText?:string;nextText?:string;small?:boolean;background?:boolean;disabled?:boolean;hideOnSinglePage?:boolean}>(),{total:0,pageSize:10,currentPage:1,pagerCount:7,layout:'prev, pager, next, jumper, total',pageSizes:()=>[10,20,30,40,50,100]});const emit=defineEmits<{'update:currentPage':[page:number];'update:pageSize':[size:number];'current-change':[page:number];'size-change':[size:number];change:[currentPage:number,pageSize:number];'prev-click':[page:number];'next-click':[page:number]}>();const current=computed(()=>Math.min(pageCount.value,Math.max(1,props.currentPage||props.defaultCurrentPage||1)));const pageSize=computed(()=>props.pageSize||props.defaultPageSize||10);const pageCount=computed(()=>props.pageCount||Math.max(1,Math.ceil(props.total/pageSize.value)));const layoutParts=computed(()=>props.layout.split(',').map(item=>item.trim()).filter(Boolean));const pages=computed<Array<number|string>>(()=>{const count=pageCount.value,limit=Math.max(5,props.pagerCount);if(count<=limit)return Array.from({length:count},(_,i)=>i+1);const half=Math.floor((limit-3)/2);let start=Math.max(2,current.value-half),end=Math.min(count-1,current.value+half);if(start===2)end=limit-2;if(end===count-1)start=count-limit+3;return[1,...(start>2?['…']:[]),...Array.from({length:end-start+1},(_,i)=>start+i),...(end<count-1?['…']:[]),count]});const classes=computed(()=>['mg-pagination',{'is-small':props.small,'is-background':props.background,'is-disabled':props.disabled}]);function setPage(page:number){const next=Math.min(pageCount.value,Math.max(1,page));if(next===current.value)return;emit('update:currentPage',next);emit('current-change',next);emit('change',next,pageSize.value);if(next<current.value)emit('prev-click',next);else emit('next-click',next)}function changeSize(event:Event){const size=Number((event.target as HTMLSelectElement).value);emit('update:pageSize',size);emit('size-change',size);emit('change',current.value,size)}function jump(event:Event){setPage(Number((event.target as HTMLInputElement).value))}
</script>
<style scoped>.mg-pagination{display:flex;align-items:center;gap:8px;color:var(--mg-color-text-regular,#424a57);font-size:14px}.mg-pagination__pager{display:flex;gap:4px}.mg-pagination__button{box-sizing:border-box;min-width:32px;height:32px;padding:0 8px;color:inherit;cursor:pointer;background:#fff;border:1px solid var(--mg-color-border,#dcdde1);border-radius:3px}.mg-pagination__button:hover:not(:disabled),.mg-pagination__button.is-active{color:#fff;background:var(--mg-color-primary,#0052d9);border-color:var(--mg-color-primary,#0052d9)}.mg-pagination__button:disabled{cursor:not-allowed;opacity:.45}.mg-pagination__button.is-more{border-color:transparent}.mg-pagination__sizes{height:32px;border:1px solid var(--mg-color-border,#dcdde1);border-radius:3px}.mg-pagination__jumper input{box-sizing:border-box;width:52px;height:32px;text-align:center;border:1px solid var(--mg-color-border,#dcdde1);border-radius:3px}.mg-pagination.is-background .mg-pagination__button{background:var(--mg-color-fill-light,#f5f6f7);border-color:transparent}.mg-pagination.is-background .mg-pagination__button.is-active{background:var(--mg-color-primary,#0052d9)}.mg-pagination.is-small .mg-pagination__button,.mg-pagination.is-small .mg-pagination__sizes,.mg-pagination.is-small .mg-pagination__jumper input{min-width:24px;height:24px;font-size:12px}</style>
